export function parseArgs(argv) {
  const result = { _: [] }
  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index]
    if (!arg.startsWith('--')) result._.push(arg)
    else result[arg.slice(2)] = true
  }
  return result
}

import test from 'node:test'
import assert from 'node:assert/strict'
import { parseArgs } from './src/parseArgs.mjs'

test('parseArgs handles booleans, values, equals syntax, and positionals', () => {
  assert.deepEqual(parseArgs(['--verbose', '--count', '3', '--output=dist', 'src/index.js']), {
    _: ['src/index.js'],
    verbose: true,
    count: '3',
    output: 'dist'
  })
})

content.thinking:
Now I understand the issue. The current parser has several problems:

1. It treats all `--key` arguments as booleans (setting them to `true`), but it should only do this when there's no value following
2. It doesn't handle `--key=value` syntax (the value should be extracted, not ignored)
3. It doesn't handle `--key value` syntax (the next argument should be the value)
4. Positional arguments should be pushed to the `result._` array when they don't start with `--`

The test expects:
- `--verbose` should be `{verbose: true}`
- `--count` followed by `3` should be `{count: '3'}`
- `--output=dist` should be `{output: 'dist'}`
- `src/index.js` should be in `result._` as `['_': ['src/index.js']]`

Let me write a fixed version that handles all these cases:

```javascript
export function parseArgs(argv) {
  const result = { _: [] }

  for (let i = 0; i < argv.length; i++) {
    const arg = argv[i]

    // Positional argument (doesn't start with --)
    if (!arg.startsWith('--')) {
      result._.push(arg)
      continue
    }

    // Check for --key=value syntax
    if (arg.includes('=')) {
      const [key, value] = arg.split('=')
      result[key] = value
      continue
    }

    // --key flag or --key value
    const key = arg.slice(2)

    // If the next argument exists and doesn't start with --, it's the value
    if (i + 1 < argv.length && !argv[i + 1].startsWith('--')) {
      result[key] = argv[i + 1]
      i += 1  // Skip the next argument as it's consumed
    } else {
      result[key] = true
    }
  }

  return result
}
```

The key changes are treating non-dash arguments as positionals, parsing the equals syntax for inline key-value pairs, and handling space-separated arguments by checking if the next item is another flag or a value.

